      "type": "codeBlock",
      "content": [
        {
          "type": "text",
          "text": "function factorial(n) {\n  if (!Number.isInteger(n)) throw new TypeError('n must be an integer');\n  if (n < 0) throw new RangeError('n must be >= 0');\n  let result = 1n;\n  const N = BigInt(n);\n  for (let i = 2n; i <= N; i++) {\n    result *= i;\n  }\n  return result; // BigInt\n}\n\n// Примеры\nconsole.log(factorial(0).toString());  // \"1\"\nconsole.log(factorial(5).toString());  // \"120\"\nconsole.log(factorial(25).toString()); // \"15511210043330985984000000\""
        }
      ]
    },
