        {
          "type": "text",
          "text": "function comb(n, k) {\n  if (!Number.isInteger(n) || !Number.isInteger(k)) {\n    throw new TypeError(\"n и k должны быть целыми числами\");\n  }\n  if (n < 0 || k < 0 || k > n) return 0n;\n  // Симметрия: C(n, k) = C(n, n-k)\n  k = Math.min(k, n - k);\n  let N = BigInt(n);\n  let K = BigInt(k);\n  let res = 1n;\n  for (let i = 1n; i <= K; i++) {\n    res = (res * (N - K + i)) / i; // Деление всегда целое\n  }\n  return res; // BigInt\n}\n\n// Примеры:\nconsole.log(comb(5, 2).toString());    // \"10\"\nconsole.log(comb(52, 5).toString());   // \"2598960\"\nconsole.log(comb(100, 50).toString()); // \"100891344545564193334812497256\""
