    {
      "type": "codeBlock",
      "attrs": {
        "language": "js"
      },
      "content": [
        {
          "type": "text",
          "text": "// Комбинации по модулю простого p, корректно, когда p > n\nfunction modPow(a, e, p) {\n  a = BigInt(a) % BigInt(p);\n  e = BigInt(e);\n  p = BigInt(p);\n  let r = 1n;\n  while (e > 0n) {\n    if (e & 1n) r = (r * a) % p;\n    a = (a * a) % p;\n    e >>= 1n;\n  }\n  return r;\n}\n\nfunction modInv(a, p) {\n  // p — простое; обратный по малой теореме Ферма\n  return modPow(a, BigInt(p) - 2n, p);\n}\n\nfunction combModPrime(n, k, p) {\n  if (!Number.isInteger(n) || !Number.isInteger(k)) {\n    throw new TypeError(\"n и k должны быть целыми числами\");\n  }\n  if (n < 0 || k < 0 || k > n) return 0n;\n  if (p <= n) {\n    throw new Error(\"Этот метод корректен только если p > n. Для общего случая используйте, например, теорему Лукаса.\");\n  }\n  k = Math.min(k, n - k);\n  let N = BigInt(n);\n  let K = BigInt(k);\n  let P = BigInt(p);\n  let res = 1n;\n  for (let i = 1n; i <= K; i++) {\n    res = (res * (N - K + i)) % P;\n    res = (res * modInv(i, P)) % P;\n  }\n  return res;\n}\n\n// Пример:\nconsole.log(combModPrime(5, 2, 1000000007n).toString()); // \"10\""
