          "type": "text",
          "text": "function factorizeTrialDivision(n) {\n  const factors = [];\n  let x = n;\n\n  let count = 0;\n  while (x % 2 === 0) {\n    x /= 2;\n    count++;\n  }\n  if (count > 0) factors.push([2, count]);\n\n  let p = 3;\n  while (p * p <= x) {\n    count = 0;\n    while (x % p === 0) {\n      x /= p;\n      count++;\n    }\n    if (count > 0) factors.push([p, count]);\n    p += 2;\n  }\n\n  if (x > 1) factors.push([x, 1]);\n  return factors; // массив пар [простое, степень]\n}\n\nfunction sumDivisorsByFactorization(n) {\n  if (!Number.isInteger(n)) throw new Error(\"n must be integer\");\n  if (n === 0) throw new Error(\"sigma(0) is undefined\");\n  n = Math.abs(n);\n  if (n === 1) return 1;\n\n  const factors = factorizeTrialDivision(n);\n  let result = 1;\n  for (const [p, a] of factors) {\n    // Геометрическая прогрессия: 1 + p + p^2 + ... + p^a = (p^(a+1) - 1)/(p - 1)\n    let termNum = 1; // p^(a+1)\n    for (let i = 0; i < a + 1; i++) termNum *= p; // безопасно для умеренных n\n    const term = (termNum - 1) / (p - 1);\n    result *= term;\n  }\n  return result;\n}\n\nconsole.log(sumDivisorsByFactorization(36)); // 91\nconsole.log(sumDivisorsByFactorization(1));  // 1"
