252 = 198 · 1 + 54     → заменяем на (198, 54)
198 = 54 · 3 + 36      → (54, 36)
54 = 36 · 1 + 18       → (36, 18)
36 = 18 · 2 + 0        → НОД = 18"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Варианты реализации"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Через вычитание: пока a ≠ b, вычитать меньшее из большего. Медленнее, но наглядно."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Через деление с остатком (классический вариант): заменять (a, b) на (b, a mod b). Быстро и просто."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Рекурсивно или итеративно — эквивалентно по сути."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Код: классический и расширенный алгоритм (JavaScript)"}]},{"type":"codeBlock","content":[{"type":"text","text":"// НОД: классический алгоритм Евклида (итеративно)
function gcd(a, b) {
  a = Math.abs(a);
  b = Math.abs(b);
  if (a === 0 && b === 0) return 0; // по договорённости
  while (b !== 0) {
    const t = a % b;
    a = b;
    b = t;
  }
  return a;
}

// НОК через НОД (с защитой от переполнения в JS для целых до Number.MAX_SAFE_INTEGER)
function lcm(a, b) {
  if (a === 0 || b === 0) return 0;
  return Math.abs((a / gcd(a, b)) * b);
}

// Расширенный алгоритм Евклида: возвращает (g, x, y) такие, что a*x + b*y = g = gcd(a,b)
function extendedGCD(a, b) {
  let old_r = Math.abs(a), r = Math.abs(b);
  let old_s = 1, s = 0;
  let old_t = 0, t = 1;

  while (r !== 0) {
    const q = Math.floor(old_r / r);
    [old_r, r] = [r, old_r - q * r];
    [old_s, s] = [s, old_s - q * s];
    [old_t, t] = [t, old_t - q * t];
  }
  // old_r = gcd, коэффициенты Безу: old_s, old_t
  // Восстановим знак в зависимости от исходных a, b
  if (a < 0) old_s = -old_s;
  if (b < 0) old_t = -old_t;
  return { g: old_r, x: old_s, y: old_t };
}

// Обратный по модулю m (предполагается m > 1). Если не существует — возвращаем null.
function modInverse(a, m) {
  const { g, x } = extendedGCD(a, m);
  if (g !== 1) return null; // обратного нет, a и m не взаимно просты
  // нормализуем в [0, m)
  return ((x % m) + m) % m;
}

// Примеры
console.log(gcd(252, 198)); // 18
console.log(lcm(12, 18));   // 36
console.log(modInverse(3, 11)); // 4, потому что 3*4 ≡ 1 (mod 11)"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Код: классический и расширенный алгоритм (Python)"}]},{"type":"codeBlock","content":[{"type":"text","text":"def gcd(a: int, b: int) -> int:
    a, b = abs(a), abs(b)
    if a == 0 and b == 0:
        return 0  # по договорённости
    while b:
        a, b = b, a % b
    return a

def lcm(a: int, b: int) -> int:
    if a == 0 or b == 0:
        return 0
    return abs(a // gcd(a, b) * b)

# Расширенный алгоритм Евклида
from typing import Tuple

def extended_gcd(a: int, b: int) -> Tuple[int, int, int]:
    old_r, r = abs(a), abs(b)
    old_s, s = 1, 0
    old_t, t = 0, 1
    while r:
        q = old_r // r
        old_r, r = r, old_r - q * r
        old_s, s = s, old_s - q * s
        old_t, t = t, old_t - q * t
    # Корректируем знаки
    if a < 0:
        old_s = -old_s
    if b < 0:
        old_t = -old_t
    return old_r, old_s, old_t  # gcd, x, y

# Обратный по модулю
def mod_inverse(a: int, m: int):
    g, x, _ = extended_gcd(a, m)
    if g != 1:
        return None
    return (x % m + m) % m

print(gcd(252, 198))  # 18
print(lcm(12, 18))    # 36
print(mod_inverse(3, 11))  # 4"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Почему это работает (корректность и завершение)"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Инвариант: НОД(a, b) = НОД(b, a mod b). Любой общий делитель a и b делит и остаток a mod b, и наоборот."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Завершение: последовательность остатков строго убывает и достигает 0 за O(log min(a, b)) шагов деления."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Сложность"}]},{"type":"paragraph","content":[{"type":"text","text":"В классической модели — O(log min(a, b)) операций деления. Важна и практическая скорость: вариант с остатком значительно быстрее варианта с вычитанием."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Граничные случаи и практические советы"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"НОД(a, 0) = |a|; НОД(0, 0) можно определить как 0 по договорённости, но математически не определён."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Используйте |a| и |b|: знак на НОД не влияет, НОД всегда неотрицателен."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Следите за переполнением при НОК: вычисляйте (a / НОД(a, b)) * b вместо a * b."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Для очень больших чисел используйте BigInt/библиотеки больших чисел."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"При вычислении обратного по модулю убедитесь, что НОД(a, m) = 1; иначе обратного нет."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Типичные вопросы на собеседовании"}]},{"type":